def format_csv_output(data: list, columns: list = None, delimiter: str = ",", include_header: bool = True) -> dict:
    """Format data as CSV string with automatic column inference.

    Args:
        data: List of dicts or list of lists
        columns: Optional column names (inferred if not provided)
        delimiter: Column separator
        include_header: Whether to include header row

    Returns:
        dict: {'csv_string': str, 'row_count': int, 'column_count': int}
    """
    if not data:
        return {'csv_string': '', 'row_count': 0, 'column_count': 0}

    # Infer columns if not provided
    if columns is None:
        if isinstance(data[0], dict):
            # Extract keys from first dictionary
            columns = list(data[0].keys())
        elif isinstance(data[0], (list, tuple)):
            # Generate column names for list data
            columns = [f"col_{i}" for i in range(len(data[0]))]
        else:
            # Single values - treat as single column
            columns = ['value']
            data = [{'value': item} if not isinstance(item, dict) else item for item in data]

    lines = []

    # Add header if requested
    if include_header:
        lines.append(delimiter.join(str(col) for col in columns))

    # Add data rows
    for item in data:
        if isinstance(item, dict):
            row = [str(item.get(col, '')) for col in columns]
        elif isinstance(item, (list, tuple)):
            row = [str(val) for val in item]
        else:
            row = [str(item)]
        lines.append(delimiter.join(row))

    csv_string = '\n'.join(lines)

    return {
        'csv_string': csv_string,
        'row_count': len(data),
        'column_count': len(columns)
    }

def paginate_api_results(api_function: str, api_params: dict = None, page_param: str = "page", max_pages: int = 100, dedupe_key: str = "id") -> dict:
    """Collect all results from a paginated API with deduplication.

    Returns:
        dict: {'items': list, 'total_count': int, 'pages_fetched': int, 'duplicates_removed': int, 'instructions': str}
    """
    if api_params is None:
        api_params = {}

    # This tool provides instructions for the agent to manually paginate
    # since we cannot directly call arbitrary API functions from within a tool

    instructions = f"""To paginate {api_function}:

1. Start with {page_param}=1
2. Call {api_function} with parameters: {api_params}
3. Collect the results and check for the '{dedupe_key}' field
4. Increment {page_param} and repeat until:
   - No more results are returned
   - Empty list is returned
   - You reach page {max_pages}
5. Track unique items by '{dedupe_key}' to avoid duplicates
6. Combine all unique items into a single list

Example pseudo-code:
all_items = []
seen_ids = set()
for page in range(1, {max_pages + 1}):
    results = {api_function}({page_param}=page, **{api_params})
    if not results:
        break
    for item in results:
        item_id = item.get('{dedupe_key}')
        if item_id not in seen_ids:
            seen_ids.add(item_id)
            all_items.append(item)
"""

    return {
        'items': [],
        'total_count': 0,
        'pages_fetched': 0,
        'duplicates_removed': 0,
        'instructions': instructions,
        'note': 'This tool provides pagination instructions. Execute the pagination manually following the instructions.'
    }

