def paginate_api_results(api_function_name: str, pagination_key: str = 'next', max_pages: int = 50, initial_params: dict = None) -> dict:
    """
    Automatically paginate through API results that use cursor/next-page pagination.

    Args:
        api_function_name: Name of the API function to call (e.g., 'appworld_api_call')
        pagination_key: JSON key containing next page URL/token (default: 'next')
        max_pages: Maximum number of pages to fetch (default: 50)
        initial_params: Dictionary of parameters for the first API call (optional)

    Returns:
        dict: {
            'all_items': list of all collected items,
            'total_pages': number of pages fetched,
            'total_items': total count of items
        }
    """
    import json

    if initial_params is None:
        initial_params = {}

    all_items = []
    pages_fetched = 0

    # Get the API function from available tools
    api_func = globals().get(api_function_name)
    if not api_func:
        return {
            'error': f'API function {api_function_name} not found',
            'all_items': [],
            'total_pages': 0,
            'total_items': 0
        }

    # Make first API call
    try:
        response = api_func(**initial_params)
        pages_fetched += 1

        # Extract items from response
        if isinstance(response, dict):
            # Common patterns for item lists
            items = response.get('items', response.get('data', response.get('results', [])))
            if isinstance(items, list):
                all_items.extend(items)

            # Check for pagination
            next_url = response.get(pagination_key)

            # Continue fetching pages
            while next_url and pages_fetched < max_pages:
                # Update params with next page URL/token
                next_params = initial_params.copy()

                # Handle different pagination styles
                if pagination_key == 'next' and isinstance(next_url, str):
                    # Full URL pagination - extract endpoint and params
                    if '?' in next_url:
                        endpoint, query = next_url.split('?', 1)
                        next_params['endpoint'] = endpoint
                        # Parse query parameters
                        for param in query.split('&'):
                            if '=' in param:
                                key, value = param.split('=', 1)
                                if 'params' not in next_params:
                                    next_params['params'] = {}
                                next_params['params'][key] = value
                else:
                    # Token-based pagination
                    if 'params' not in next_params:
                        next_params['params'] = {}
                    next_params['params'][pagination_key] = next_url

                response = api_func(**next_params)
                pages_fetched += 1

                items = response.get('items', response.get('data', response.get('results', [])))
                if isinstance(items, list):
                    all_items.extend(items)

                next_url = response.get(pagination_key)

        return {
            'all_items': all_items,
            'total_pages': pages_fetched,
            'total_items': len(all_items)
        }

    except Exception as e:
        return {
            'error': str(e),
            'all_items': all_items,
            'total_pages': pages_fetched,
            'total_items': len(all_items)
        }
